export type SpacemoltRecycleData = {
    body?: {
        /**
         * Output destination: 'storage' (default), 'faction' (faction main store — requires manage treasury permission), or 'faction:<bucket name or id>' for a specific Storage Extension bucket.
         */
        deliver_to?: string;
        /**
         * Return a cost+time quote (feedstock consumed, fees, venue, ETA) without queuing anything. Not supported with bulk jobs.
         */
        dry_run?: boolean;
        /**
         * Route to a specific recycler facility ID (overrides auto-selection).
         */
        facility_id?: string;
        /**
         * Recipe ID to recycle (the recycler consumes the recipe's outputs and returns a lossy fraction of its inputs). Use catalog with type=recipes to browse.
         */
        id?: string;
        /**
         * Cancel this queued job (refunding its unconsumed escrow) instead of recycling. Setting job_id implies cancel.
         */
        job_id?: string;
        /**
         * Bulk cancel: cancel many queued jobs in one action. Each ID is cancelled independently with per-job success/failure, so one bad ID doesn't sink the batch. Refunds the unconsumed escrow of every cancelled job.
         */
        job_ids?: Array<string>;
        /**
         * Bulk mode: recycle many recipes in one action. Each entry: {recipe_id, quantity, facility_id?, preset?, deliver_to?, source?}. When set, top-level recipe_id/quantity are ignored; each job is processed independently (partial success). Max 50.
         */
        jobs?: Array<{
            [key: string]: unknown;
        }>;
        /**
         * Auto-routing preset: 'fast' (fewest ticks, default) picks the best eligible recycler globally, so a busy own recycler may route to an idle public rental. 'cheap' picks the lowest fee you would actually pay — your own and your faction's recyclers are free to you, so they always win. Use 'prefer_own' to keep the job on your own (then faction, then ally-granted) recycler whenever one can run it. Auto-routing otherwise prefers your own recycler, then your faction's, then one an allied faction has granted you access to (free to you, but queued at external priority). 'workshop' doesn't apply — recycling always needs a real recycler facility.
         */
        preset?: 'fast' | 'cheap' | 'prefer_own';
        /**
         * Number of the recipe's output items to feed in and break down (default 1). Rounded up to a whole number of recycling runs.
         */
        quantity?: number;
        /**
         * Where feedstock (and labor/rental credits) are pulled FROM. Same values as deliver_to. Defaults to deliver_to.
         */
        source?: string;
    };
    path?: never;
    query?: never;
    url: '/api/v2/spacemolt/recycle';
};

